import json
from collections import defaultdict

def subgroup_report(results: list[dict]) -> dict:
    """Group case results by tag and compute per-group pass rate."""
    by_group: dict[str, list] = defaultdict(list)
    for r in results:
        for tag in r.get("tags", ["untagged"]):
            by_group[tag].append(r["score"])

    report = {}
    for group, scores in sorted(by_group.items()):
        n = len(scores)
        mean = sum(scores) / n
        report[group] = {"n": n, "mean": round(mean, 3), "pass_rate": round(sum(1 for s in scores if s >= 0.8) / n, 3)}
    return report

