def length_bucket_report(results: list[dict]) -> dict:
    buckets: dict[str, list] = {"short": [], "medium": [], "long": [], "very_long": []}
    for r in results:
        chars = len(r.get("input", ""))
        if chars < 200:
            buckets["short"].append(r["score"])
        elif chars < 1000:
            buckets["medium"].append(r["score"])
        elif chars < 5000:
            buckets["long"].append(r["score"])
        else:
            buckets["very_long"].append(r["score"])

    return {
        k: {"n": len(v), "mean": round(sum(v)/len(v), 3) if v else None}
        for k, v in buckets.items()
    }

def cluster_failures(results: list[dict], threshold: float = 0.5) -> list[dict]:
    """Return failing cases sorted by score, annotated for review."""
    failing = [r for r in results if r.get("score", 1.0) < threshold]
    failing.sort(key=lambda r: r["score"])

    for i, r in enumerate(failing):
        # Truncate for display
        r["input_preview"]  = r.get("input", "")[:120]
        r["output_preview"] = r.get("output", "")[:120]
    return failing

def find_common_patterns(failing: list[dict]) -> dict:
    """Naive frequency analysis on input words for failure clustering."""
    from collections import Counter
    words = Counter()
    for r in failing:
        words.update(r.get("input", "").lower().split())
    # Remove stop words
    stop = {"the","a","an","is","in","of","to","and","for","with","that","this","it"}
    return {w: c for w, c in words.most_common(20) if w not in stop}

from collections import Counter

def detect_systematic_failure(failing_cases: list[dict], min_frequency: int = 3) -> list[dict]:
    """
    Look for shared surface features among failing cases.
    Returns features that appear in at least min_frequency failing cases.
    """
    feature_counts: Counter = Counter()
    for case in failing_cases:
        text = (case.get("input", "") + " " + case.get("output", "")).lower()
        # Feature: input length bucket
        length = len(case.get("input", ""))
        if length > 5000:
            feature_counts["long_input (>5000 chars)"] += 1
        elif length < 50:
            feature_counts["short_input (<50 chars)"] += 1
        # Feature: specific tag
        for tag in case.get("tags", []):
            feature_counts[f"tag:{tag}"] += 1
        # Feature: output type
        if case.get("output", "").startswith("{"):
            feature_counts["output_starts_with_json"] += 1

    return [
        {"feature": feat, "count": cnt, "rate": round(cnt / len(failing_cases), 2)}
        for feat, cnt in feature_counts.items()
        if cnt >= min_frequency
    ]
